SELECT COUNT(DISTINCT participant_id)
FROM measurements
WHERE BMI_class = 'Underweight';

SELECT users.user_name, physiological_measurements.physiological_measurement_id
FROM users
INNER JOIN physiological_measurements ON users.user_id = physiological_measurements.measurement_id;

SELECT branch_name
FROM branches
WHERE contact_email LIKE '%@example.com' AND establishment_date > '1990-01-01';

SELECT access_logs.measurement_id, access_logs.access_date
FROM access_logs
LEFT JOIN measurements ON access_logs.measurement_id = measurements.measurement_id;

SELECT participant_name, email 
FROM participants 
WHERE participant_id IN (
  SELECT DISTINCT participant_id 
  FROM measurements
);

SELECT created_by, COUNT(note_id) as total_notes
FROM notes
GROUP BY created_by;
